defmodule MyApp.CommandService do
  @moduledoc """
  Secure command execution service with allowlisted commands.
  Never passes raw user input to a shell.
  """

  # Allowlist of permitted commands with their executable paths
  @allowed_commands %{
    "disk_usage" => {"/usr/bin/df", ["-h"]},
    "list_containers" => {"/usr/bin/docker", ["ps", "--format", "table {{.Names}}\t{{.Status}}"]},
    "system_uptime" => {"/usr/bin/uptime", []},
    "memory_info" => {"/usr/bin/free", ["-m"]},
    "check_service" => {"/usr/bin/systemctl", ["status"]},  # requires a safe argument
    "ping_host" => {"/usr/bin/ping", ["-c", "3"]}           # requires a safe argument
  }

  # Commands that accept one additional sanitized argument
  @commands_with_arg MapSet.new(["check_service", "ping_host"])

  @doc """
  Executes a pre-approved command by name.
  Returns {:ok, output} or {:error, reason}.
  """
  def execute(command_name, arg \\ nil) do
    with :ok <- validate_command(command_name),
         :ok <- validate_arg(command_name, arg),
         {:ok, {executable, base_args}} <- get_command(command_name),
         args <- build_args(command_name, base_args, arg) do
      run_command(executable, args)
    end
  end

  defp validate_command(name) when is_binary(name) do
    if Map.has_key?(@allowed_commands, name) do
      :ok
    else
      {:error, :command_not_allowed}
    end
  end

  defp validate_command(_), do: {:error, :invalid_command_name}

  defp validate_arg(command_name, arg) do
    cond do
      command_name in @commands_with_arg and is_nil(arg) ->
        {:error, :argument_required}

      command_name in @commands_with_arg ->
        sanitize_arg(arg)

      not is_nil(arg) ->
        {:error, :argument_not_expected}

      true ->
        :ok
    end
  end

  # Strict allowlist for argument characters: alphanumeric, dots, hyphens, underscores
  defp sanitize_arg(arg) when is_binary(arg) do
    if Regex.match?(~r/\A[a-zA-Z0-9.\-_]{1,253}\z/, arg) do
      :ok
    else
      {:error, :invalid_argument}
    end
  end

  defp sanitize_arg(_), do: {:error, :invalid_argument}

  defp get_command(name) do
    case Map.fetch(@allowed_commands, name) do
      {:ok, cmd} -> {:ok, cmd}
      :error -> {:error, :command_not_found}
    end
  end

  defp build_args(command_name, base_args, arg) do
    if command_name in @commands_with_arg do
      base_args ++ [arg]
    else
      base_args
    end
  end

  defp run_command(executable, args) do
    try do
      case System.cmd(executable, args, stderr_to_stdout: true, timeout: 30_000) do
        {output, 0} ->
          {:ok, %{output: output, exit_code: 0}}

        {output, exit_code} ->
          {:error, %{output: output, exit_code: exit_code}}
      end
    rescue
      e in ErlangError ->
        {:error, %{reason: :execution_failed, detail: inspect(e)}}
    end
  end
end

defmodule MyAppWeb.CommandController do
  use MyAppWeb, :controller

  alias MyApp.CommandService

  require Logger

  def execute(conn, %{"command" => command_name} = params) do
    arg = Map.get(params, "arg")

    Logger.info("Command request: #{command_name}, arg: #{inspect(arg)}, user: #{inspect(conn.assigns[:current_user])}")

    case CommandService.execute(command_name, arg) do
      {:ok, result} ->
        json(conn, %{status: "success", output: result.output, exit_code: result.exit_code})

      {:error, :command_not_allowed} ->
        conn
        |> put_status(:forbidden)
        |> json(%{status: "error", message: "Command not in allowlist"})

      {:error, :invalid_argument} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Invalid argument (alphanumeric, dots, hyphens, underscores only)"})

      {:error, :argument_required} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "This command requires an argument"})

      {:error, %{output: output, exit_code: exit_code}} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", output: output, exit_code: exit_code})

      {:error, reason} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{status: "error", message: inspect(reason)})
    end
  end

  def execute(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{status: "error", message: "Missing 'command' parameter"})
  end

  def list_commands(conn, _params) do
    commands = ["disk_usage", "list_containers", "system_uptime", "memory_info", "check_service", "ping_host"]
    json(conn, %{available_commands: commands})
  end
end